function timeConversion(millisec) {
    var seconds = (millisec / 1000).toFixed(1);
    var minutes = (millisec / (1000 * 60)).toFixed(1);
    var hours = (millisec / (1000 * 60 * 60)).toFixed(1);
    var days = (millisec / (1000 * 60 * 60 * 24)).toFixed(1);
    if (seconds < 60) { return seconds + " Sec"; }
    else if (minutes < 60) { return minutes + " Min"; }
    else if (hours < 24) { return hours + " Hrs"; }
    else { return days + " Days" }
}
msg.payload = timeConversion(msg.payload.uptime * 1000);
return msg;

let data = msg.payload;
let lines = data.split('\n');
let totalSize = 0;
let totalUsed = 0.256;
let totalAvailable = 0;
let regex = /(\S+)\s+([\d.]+)([MKG]?)\s+([\d.]+)([MKG]?)\s+([\d.]+)([MKG]?)\s+(\d+)%/;
function mbToGb(value, unit) {
    switch (unit) {
        case 'G': return value;
        case 'M': return value / 1024;
        case 'K': return value / 1024 / 1024;
        default: return 0;
    }
}
for (let line of lines) {
    let match = line.match(regex);
    if (match && (match[1] === '/dev/root' || match[1] === '/dev/mmcblk0p6')) {
        totalSize += mbToGb(parseFloat(match[2]), match[3]);
        totalUsed += mbToGb(parseFloat(match[4]), match[5]);
        totalAvailable += mbToGb(parseFloat(match[6]), match[7]);
    }
}
totalUsed = totalUsed.toFixed(2);
totalAvailable = totalAvailable.toFixed(2);
totalSize = (Number(totalUsed) + Number(totalAvailable)).toFixed(2);
let usedPercentage = ((totalUsed / totalSize) * 100).toFixed(2);
let freePercentage = ((totalAvailable / totalSize) * 100).toFixed(2);
return [{payload: totalSize},{payload: totalUsed},{payload: totalAvailable},{payload: usedPercentage},{payload: freePercentage}];

const selectModel = flow.get("option_model")
let currentModel = "Current "
let object = ''
switch(selectModel) {
    case "0": currentModel += "People"; object = 'person'; break;
    case "1": currentModel += "Cat"; object = 'cat'; break;
    case "2": currentModel += "Dog"; object = 'dog'; break;
    case "3": currentModel += "Bottle"; object = 'bottle'; break;
    default: currentModel = null
}
if (currentModel) {
    const labels = msg.payload?.data?.labels ?? []
    if (!Array.isArray(labels)) { return { payload: '' } }
    const num = labels.filter(label => String(label).toLowerCase() === object).length
    currentModel += ` number: ${num}`
    return {payload: currentModel}
} else {
    return {payload: ''}
}

// Data lives at msg.payload.data
var data = msg.payload && msg.payload.data ? msg.payload.data : null;

// Drop frames with nothing detected
if (!data || !Array.isArray(data.labels) || data.labels.length === 0) {
    return null;
}

// Build a clean log entry
var out = {
    timestamp: new Date().toISOString(),
    count: data.labels.length,
    labels: data.labels,
    boxes: data.boxes || [],
    resolution: data.resolution || []
};

msg.url = "http://192.168.42.41:5000/predictions";
msg.method = "POST";
msg.headers = { "Content-Type": "application/json" };
msg.payload = JSON.stringify(out);
return msg;
